#!/usr/bin/env bash
# topic-1.sh — 编程 决策助手 for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
TOPIC="编程"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 6 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 编程 主题下的 playbook 规则组合成交互树。

基于 6 条规则:
  • 如果 学生是 6-9 岁初学者 → 则 : 则从 Scratch 或 ScratchJr 开始积木编程, 不要从文本语言开始 — 积木编程消除了语法错误障碍, 
  • 如果 学生从积木编程过渡到文本编程 → 则 : 则选 Python 而非 C++/Java 作为第一文本语言 (除非目标明确是信奥赛) — Python 语法接近自
  • 如果 开设培训机构的编程课 → 则 : 则课消 (课时消耗率) 而非招生数才是核心健康指标 — 课消 = 已消耗课时 / 已售课时
  • 如果 设计编程课的评价体系 → 则 : 则采用「作品集 + CT 维度量规」双轨制, 不要只用选择题考试 — Brennan & Resnick CT 框架
  • 如果 家长问「学编程对升学有帮助吗」 → 则 : 则诚实回答: (a) 直接加分路径仅剩 NOI/IOI 竞赛省一等奖以上 (各省政策不同, 需核实当年规定); (b
  • 如果 引入 AI 辅助编程教学 (如 GitHub Copilot / Khanmigo) → 则 : 则必须: (a) 明确 AI 是助手不是替代; (b) 禁止学生直接让 AI 写完整代码 (违背学习目标); (c)

相关心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "学生是 6-9 岁初学者"
  "学生从积木编程过渡到文本编程"
  "开设培训机构的编程课"
  "设计编程课的评价体系"
  "家长问「学编程对升学有帮助吗」"
  "引入 AI 辅助编程教学 (如 GitHub Copilot / Khanmigo)"
)
declare -a RULE_ACTIONS=(
  ": 则从 Scratch 或 ScratchJr 开始积木编程, 不要从文本语言开始 — 积木编程消除了语法错误障碍, 让学生聚焦于逻辑和创意"
  ": 则选 Python 而非 C++/Java 作为第一文本语言 (除非目标明确是信奥赛) — Python 语法接近自然语言, 缩进强制代码结构, 交互式解释器支持即时反馈"
  ": 则课消 (课时消耗率) 而非招生数才是核心健康指标 — 课消 = 已消耗课时 / 已售课时"
  ": 则采用「作品集 + CT 维度量规」双轨制, 不要只用选择题考试 — Brennan & Resnick CT 框架三维度: 概念 (CT 概念掌握) / 实践 (编程实践能力) / 视角 (对计算的理解)"
  ": 则诚实回答: (a) 直接加分路径仅剩 NOI/IOI 竞赛省一等奖以上 (各省政策不同, 需核实当年规定); (b) 中考没有直接帮助; (c) 高考强基计划认可信奥赛成绩; (d) 真正的价值是计算思维能力, 不是升学加分"
  ": 则必须: (a) 明确 AI 是助手不是替代; (b) 禁止学生直接让 AI 写完整代码 (违背学习目标); (c) 教师必须审核 AI 生成的代码/反馈; (d) 竞赛训练中完全禁用 AI (IOI 2024+ 明确规定)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
